"""MKT Phase 2: Titus, 2 Thessalonians, 2 Peter."""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent
DRAFT = ROOT / 'data' / 'translation' / 'draft'

def load(tier, book):
    p = DRAFT / tier / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save(tier, book, data):
    p = DRAFT / tier / f'{book}.json'
    p.write_text(json.dumps(data, ensure_ascii=False))
    print(f'  wrote {p.relative_to(ROOT)}')

def write_book(bookid, chapters):
    for tier, key in [('literal','L'), ('mediating','M'), ('thought','T')]:
        data = load(tier, bookid)
        for ch, verses in chapters.items():
            if ch not in data:
                data[ch] = {}
            for v, tiers in verses.items():
                data[ch][v] = tiers[key]
        save(tier, bookid, data)

# ── TITUS ─────────────────────────────────────────────────────────────────
write_book('titus', {
  "1": {
    "1": {"L":"Paul, a servant of God and apostle of Jesus Christ, for the faith of God's elect and the knowledge of the truth that is according to godliness,","M":"Paul, a servant of God and an apostle of Jesus Christ to further the faith of God's elect and their knowledge of the truth that leads to godliness—","T":"I, Paul, am a servant of God and an apostle of Jesus Christ. My mission is to strengthen the faith of those God has chosen and to deepen their knowledge of the truth that leads to godly living—"},
    "2": {"L":"in hope of eternal life, which God, who cannot lie, promised before eternal ages,","M":"in the hope of eternal life, which God, who does not lie, promised before the beginning of time,","T":"all of this resting on the hope of eternal life—a life that God, who never lies, promised before time began."},
    "3": {"L":"but in his own time he manifested his word in the proclamation with which I was entrusted according to the command of God our Savior—","M":"and which now at his appointed season he has brought to light through the preaching entrusted to me by the command of God our Savior,","T":"At just the right moment he revealed this through the preaching I was entrusted with, by the command of God our Savior."},
    "4": {"L":"to Titus, my true child in the common faith: Grace and peace from God the Father and Christ Jesus our Savior.","M":"To Titus, my true son in our common faith: Grace and peace from God the Father and Christ Jesus our Savior.","T":"I'm writing to Titus—my genuine son in the faith we share. May God the Father and Christ Jesus our Savior give you grace and peace."},
    "5": {"L":"For this reason I left you in Crete: so that you would set in order what remained and appoint elders in every city, as I directed you—","M":"The reason I left you in Crete was that you might put in order what was left unfinished and appoint elders in every town, as I directed you.","T":"I left you in Crete to do two things: finish what still needed doing and appoint elders in every town, as I instructed you."},
    "6": {"L":"if any man is above reproach, the husband of one wife, having children who believe and are not accused of recklessness or rebellion.","M":"An elder must be blameless, faithful to his wife, a man whose children believe and are not open to the charge of being wild and disobedient.","T":"An elder must be above reproach—faithful to his wife and with children who believe and have a good reputation—not wild or rebellious."},
    "7": {"L":"For the overseer, as God's steward, must be above reproach: not self-willed, not quick-tempered, not addicted to wine, not violent, not pursuing dishonest gain;","M":"Since an overseer manages God's household, he must be blameless—not overbearing, not quick-tempered, not given to drunkenness, not violent, not pursuing dishonest gain.","T":"As God's household manager, an overseer must be blameless—not arrogant, not hot-headed, not a drinker, not violent, not greedy for money."},
    "8": {"L":"but hospitable, a lover of goodness, self-controlled, upright, holy, disciplined,","M":"Rather, he must be hospitable, one who loves what is good, who is self-controlled, upright, holy and disciplined.","T":"Instead he must be hospitable, love what is good, be self-controlled, fair, holy, and disciplined."},
    "9": {"L":"holding firmly to the faithful word according to the teaching, so that he may be able both to exhort with sound doctrine and to refute those who contradict.","M":"He must hold firmly to the trustworthy message as it has been taught, so that he can encourage others by sound doctrine and refute those who oppose it.","T":"He must hold firmly to the trustworthy teaching he received, so he can encourage others with sound doctrine and also refute those who argue against it."},
    "10": {"L":"For there are many who are insubordinate, empty talkers and deceivers, especially those of the circumcision,","M":"For there are many rebellious people, full of meaningless talk and deception, especially those of the circumcision group.","T":"There are many people who defy authority—empty talkers and deceivers, especially those from the circumcision party."},
    "11": {"L":"who must be silenced, since they are upsetting entire households by teaching things they should not teach for the sake of shameful gain.","M":"They must be silenced, because they are disrupting whole households by teaching things they ought not to teach—and that for the sake of dishonest gain.","T":"They must be stopped—they are ruining entire families by teaching what they shouldn't, all for financial gain."},
    "12": {"L":"One of them, one of their own prophets, has said: 'Cretans are always liars, evil beasts, lazy gluttons.'","M":"One of Crete's own prophets has said it: 'Cretans are always liars, evil brutes, lazy gluttons.'","T":"Even one of Crete's own prophets wrote: 'Cretans are always liars, brutal animals, and lazy gluttons.'"},
    "13": {"L":"This testimony is true. For this reason, rebuke them sharply, so that they may be sound in the faith,","M":"This saying is true. Therefore rebuke them sharply, so that they will be sound in the faith","T":"This reputation is well-earned. For this reason, correct them firmly—so they'll become healthy in the faith"},
    "14": {"L":"and not paying attention to Jewish myths and commandments of men who turn away from the truth.","M":"and will pay no attention to Jewish myths or to the merely human commands of those who reject the truth.","T":"and will stop following Jewish myths and the commands of people who have turned away from the truth."},
    "15": {"L":"To the pure all things are pure; but to those who are defiled and unbelieving nothing is pure; but both their mind and their conscience are defiled.","M":"To the pure, all things are pure, but to those who are corrupted and do not believe, nothing is pure. In fact, both their minds and consciences are corrupted.","T":"For those who are spiritually pure, everything is pure. But for those who are corrupt and unbelieving, nothing is pure—both their thinking and their conscience have been contaminated."},
    "16": {"L":"They profess to know God, but by their works they deny him, being detestable and disobedient, and for every good work disqualified.","M":"They claim to know God, but by their actions they deny him. They are detestable, disobedient and unfit for doing anything good.","T":"They claim to know God, but their actions show otherwise. They are detestable and disobedient—completely useless for anything good."}
  },
  "2": {
    "1": {"L":"But as for you, speak what is fitting for sound doctrine:","M":"You, however, must teach what is appropriate to sound doctrine.","T":"But you must teach what is consistent with sound doctrine."},
    "2": {"L":"Older men are to be sober-minded, worthy of respect, self-controlled, sound in faith, in love, in endurance.","M":"Teach the older men to be temperate, worthy of respect, self-controlled, and sound in faith, in love and in endurance.","T":"Teach older men to be temperate, dignified, self-controlled, and firm in faith, love, and endurance."},
    "3": {"L":"Older women likewise are to be reverent in behavior, not malicious gossips, not enslaved to much wine, teachers of what is good,","M":"Likewise, teach the older women to be reverent in the way they live, not to be slanderers or addicted to much wine, but to teach what is good.","T":"Similarly, teach older women to live in a way that honors God. They must not slander others or be heavy drinkers. Instead, they should teach what is good."},
    "4": {"L":"so that they may train the young women to love their husbands and children,","M":"Then they can urge the younger women to love their husbands and children,","T":"That way they can train the younger women to love their husbands and children,"},
    "5": {"L":"to be self-controlled, pure, working at home, kind, submissive to their own husbands, so that the word of God will not be dishonored.","M":"to be self-controlled and pure, to be busy at home, to be kind, and to be subject to their husbands, so that no one will malign the word of God.","T":"to be self-controlled and pure, to take good care of their homes, to be kind, and to be respectful of their husbands—so no one can speak badly about God's word."},
    "6": {"L":"In the same way urge the younger men to be self-controlled,","M":"Similarly, encourage the young men to be self-controlled.","T":"Encourage the younger men to be self-controlled."},
    "7": {"L":"in all things showing yourself as a model of good works; in your teaching showing integrity, seriousness,","M":"In everything set them an example by doing what is good. In your teaching show integrity, seriousness","T":"In everything you do, show yourself as a model of good works. In your teaching, show integrity and seriousness—"},
    "8": {"L":"a sound message beyond reproach, so that the opponent may be put to shame, having nothing bad to say about us.","M":"and soundness of speech that cannot be condemned, so that those who oppose you may be ashamed because they have nothing bad to say about us.","T":"and use words that are beyond criticism—so that anyone who opposes you will be ashamed and have nothing bad to say about us."},
    "9": {"L":"Slaves are to be subject to their own masters in everything, to be well-pleasing, not argumentative,","M":"Teach slaves to be subject to their masters in everything, to try to please them, not to talk back to them,","T":"Encourage those who serve under masters to be obedient in all things, to make themselves pleasing, not to argue,"},
    "10": {"L":"not stealing, but showing all good faith, so that in everything they may adorn the teaching of God our Savior.","M":"and not to steal from them, but to show that they can be fully trusted, so that in every way they will make the teaching about God our Savior attractive.","T":"and not to steal—but to show complete trustworthiness, so that in every way they make the teaching about God our Savior more attractive."},
    "11": {"L":"For the grace of God has appeared, bringing salvation to all men,","M":"For the grace of God has appeared that offers salvation to all people.","T":"For God's grace has appeared, bringing the offer of salvation to every person."},
    "12": {"L":"instructing us to deny ungodliness and worldly desires, and to live sensibly and righteously and godly in this present age,","M":"It teaches us to say no to ungodliness and worldly passions, and to live self-controlled, upright and godly lives in this present age,","T":"This grace trains us to say no to ungodliness and worldly passions, and to live self-controlled, righteous, and godly lives in this present age—"},
    "13": {"L":"waiting for the blessed hope—the appearing of the glory of our great God and Savior, Jesus Christ,","M":"while we wait for the blessed hope—the appearing of the glory of our great God and Savior, Jesus Christ,","T":"while we wait eagerly for the blessed hope—the glorious appearing of our great God and Savior, Jesus Christ."},
    "14": {"L":"who gave himself for us to redeem us from all lawlessness and to purify for himself a people who are his own possession, zealous for good works.","M":"who gave himself for us to redeem us from all wickedness and to purify for himself a people that are his very own, eager to do what is good.","T":"He gave himself for us to free us from every form of wickedness and to purify for himself a people who are completely his own—passionate about doing good."},
    "15": {"L":"Speak these things and exhort and rebuke with all authority. Let no one disregard you.","M":"These, then, are the things you should teach. Encourage and rebuke with all authority. Do not let anyone despise you.","T":"Teach these things, encourage people, and correct those who are wrong. Don't let anyone dismiss your authority."}
  },
  "3": {
    "1": {"L":"Remind them to be subject to rulers and authorities, to be obedient, to be ready for every good work,","M":"Remind the people to be subject to rulers and authorities, to be obedient, to be ready to do whatever is good,","T":"Remind your people to submit to the government and its authorities, to obey them, and to be ready for every good work."},
    "2": {"L":"to slander no one, to be uncontentious, gentle, showing every consideration for all men.","M":"to slander no one, to be peaceable and considerate, and always to be gentle toward everyone.","T":"They must not slander anyone—instead they should be peaceable, gentle, and considerate toward everyone."},
    "3": {"L":"For we also were once foolish, disobedient, led astray, enslaved to various desires and pleasures, passing our days in malice and envy, hateful, hating one another.","M":"At one time we too were foolish, disobedient, deceived and enslaved by all kinds of passions and pleasures. We lived in malice and envy, being hated and hating one another.","T":"Remember, we ourselves were once foolish and disobedient—led astray, enslaved to all kinds of passions and pleasures. We lived in malice and envy, hateful and hating each other."},
    "4": {"L":"But when the kindness and love for mankind of God our Savior appeared,","M":"But when the kindness and love of God our Savior appeared,","T":"But then the kindness and love of God our Savior appeared—"},
    "5": {"L":"he saved us—not by works of righteousness that we had done, but according to his mercy—through the washing of regeneration and renewing of the Holy Spirit,","M":"he saved us, not because of righteous things we had done, but because of his mercy. He saved us through the washing of rebirth and renewing by the Holy Spirit,","T":"he saved us—not because of anything righteous we had done, but out of his own mercy. He saved us through the washing that brings new birth and renewal by the Holy Spirit,"},
    "6": {"L":"whom he poured out on us richly through Jesus Christ our Savior,","M":"whom he poured out on us generously through Jesus Christ our Savior,","T":"which he generously poured out on us through Jesus Christ our Savior."},
    "7": {"L":"so that being justified by his grace we would become heirs according to the hope of eternal life.","M":"so that, having been justified by his grace, we might become heirs having the hope of eternal life.","T":"This happened so that, having been made right with God by his grace, we would inherit the eternal life we are hoping for."},
    "8": {"L":"This saying is trustworthy, and I want you to insist on these things, so that those who have believed God may be careful to devote themselves to good works. These things are good and profitable for everyone.","M":"This is a trustworthy saying. And I want you to stress these things, so that those who have trusted in God may be careful to devote themselves to doing what is good. These things are excellent and profitable for everyone.","T":"This is absolutely trustworthy, and I want you to make this a strong emphasis—so those who trust in God will make sure they are devoted to doing good. This is excellent and helps everyone."},
    "9": {"L":"But avoid foolish disputes and genealogies and strife and quarrels about the Law, for they are useless and vain.","M":"But avoid foolish controversies and genealogies and arguments and quarrels about the law, because these are unprofitable and useless.","T":"But avoid foolish controversies, endless genealogies, and pointless arguments about the Law. They are a waste of time and ultimately useless."},
    "10": {"L":"Warn a divisive person once, and then a second time; after that have nothing to do with him,","M":"Warn a divisive person once, and then warn them a second time. After that, have nothing to do with them.","T":"Give a divisive person one warning, then a second. After that, have nothing more to do with them."},
    "11": {"L":"knowing that such a person has been perverted and is sinning, being self-condemned.","M":"You may be sure that such people are warped and sinful; they are self-condemned.","T":"You can be sure such a person is spiritually twisted and sinful—and has condemned themselves by their own actions."},
    "12": {"L":"When I send Artemas to you or Tychicus, make every effort to come to me at Nicopolis, for I have decided to spend the winter there.","M":"As soon as I send Artemas or Tychicus to you, do your best to come to me at Nicopolis, because I have decided to winter there.","T":"Once I send Artemas or Tychicus to you, do your best to come to me at Nicopolis—I've decided to spend the winter there."},
    "13": {"L":"Diligently help Zenas the lawyer and Apollos on their journey, so that they lack nothing.","M":"Do everything you can to help Zenas the lawyer and Apollos on their way and see that they have everything they need.","T":"Give Zenas the lawyer and Apollos every possible help for their journey so they don't lack anything."},
    "14": {"L":"And let our people also learn to devote themselves to good works for pressing needs, so that they will not be unfruitful.","M":"Our people must learn to devote themselves to doing what is good, in order to provide for urgent needs and not live unproductive lives.","T":"Our people must learn to devote themselves to doing good so they can provide for urgent needs and not be spiritually unproductive."},
    "15": {"L":"All who are with me greet you. Greet those who love us in faith. Grace be with all of you.","M":"Everyone with me sends you greetings. Greet those who love us in the faith. Grace be with you all.","T":"Everyone here with me sends greetings. Please greet all those who love us in the faith. Grace be with you all."}
  }
})

# ── 2 THESSALONIANS ───────────────────────────────────────────────────────
write_book('2thessalonians', {
  "1": {
    "1": {"L":"Paul and Silvanus and Timothy, to the church of the Thessalonians in God our Father and the Lord Jesus Christ:","M":"Paul, Silas and Timothy, To the church of the Thessalonians in God our Father and the Lord Jesus Christ:","T":"From Paul, Silas, and Timothy—to the church of the Thessalonians, who belong to God our Father and the Lord Jesus Christ."},
    "2": {"L":"Grace to you and peace from God the Father and the Lord Jesus Christ.","M":"Grace and peace to you from God the Father and the Lord Jesus Christ.","T":"May God the Father and the Lord Jesus Christ give you grace and peace."},
    "3": {"L":"We are bound to give thanks to God always for you, brothers, as is fitting, because your faith is growing more and more, and the love of each one of you for all the others is increasing.","M":"We ought always to thank God for you, brothers and sisters, and rightly so, because your faith is growing more and more, and the love all of you have for one another is increasing.","T":"We must always thank God for you, and rightly so—because your faith is growing more and more, and the love you have for each other keeps increasing."},
    "4": {"L":"Therefore we ourselves boast about you among the churches of God for your endurance and faith in all your persecutions and afflictions that you are enduring.","M":"Therefore, among God's churches we boast about your perseverance and faith in all the persecutions and trials you are enduring.","T":"That's why we boast about you to other churches—we tell them about the endurance and faith you show in all the persecutions and suffering you are going through."},
    "5": {"L":"This is evidence of the righteous judgment of God, so that you may be considered worthy of the kingdom of God, for which you are also suffering.","M":"All this is evidence that God's judgment is right, and as a result you will be counted worthy of the kingdom of God, for which you are suffering.","T":"All of this is a clear sign that God's judgment is fair. Because you are suffering, God considers you worthy of his kingdom—for which you are enduring all this."},
    "6": {"L":"Since indeed it is just on God's part to repay with affliction those who afflict you,","M":"God is just: He will pay back trouble to those who trouble you","T":"God's justice will ensure that those who are making you suffer will themselves suffer."},
    "7": {"L":"and to give relief to you who are afflicted along with us, when the Lord Jesus is revealed from heaven with his mighty angels,","M":"and give relief to you who are troubled, and to us as well. This will happen when the Lord Jesus is revealed from heaven in blazing fire with his powerful angels.","T":"And he will give relief to you who are suffering—and to us as well. This will happen when the Lord Jesus is revealed from heaven with his powerful angels,"},
    "8": {"L":"in flaming fire, inflicting vengeance on those who do not know God and on those who do not obey the gospel of our Lord Jesus.","M":"He will punish those who do not know God and do not obey the gospel of our Lord Jesus.","T":"bringing judgment in blazing fire on those who don't know God and who refuse to obey the gospel of our Lord Jesus."},
    "9": {"L":"These will pay the penalty of eternal destruction, away from the presence of the Lord and from the glory of his strength,","M":"They will be punished with everlasting destruction and shut out from the presence of the Lord and from the glory of his might","T":"They will be punished with eternal destruction—completely cut off from the presence of the Lord and from the glory of his power—"},
    "10": {"L":"when he comes to be glorified in his saints and to be marveled at among all who have believed—because our testimony to you was believed—on that day.","M":"on the day he comes to be glorified in his holy people and to be marveled at among all those who have believed. This includes you, because you believed our testimony to you.","T":"on the day he comes to receive glory from his holy people and to be admired by all who have believed—and this includes you, because you believed what we told you."},
    "11": {"L":"To this end we always pray for you, that our God may count you worthy of his calling and may fulfill every resolve for goodness and every work of faith with power,","M":"With this in mind, we constantly pray for you, that our God may make you worthy of his calling, and that by his power he may bring to fruition your every desire for goodness and your every deed prompted by faith.","T":"With this in mind, we pray for you constantly—asking that our God will count you worthy of the calling you received, and that his power will bring to fulfillment every good intention and every act of faith."},
    "12": {"L":"so that the name of our Lord Jesus may be glorified in you, and you in him, according to the grace of our God and the Lord Jesus Christ.","M":"We pray this so that the name of our Lord Jesus may be glorified in you, and you in him, according to the grace of our God and the Lord Jesus Christ.","T":"We want this so that the name of our Lord Jesus may be glorified in you and you in him—all by the grace of our God and the Lord Jesus Christ."}
  },
  "2": {
    "1": {"L":"Now we ask you, brothers, with regard to the coming of our Lord Jesus Christ and our gathering together to him,","M":"Concerning the coming of our Lord Jesus Christ and our being gathered to him, we ask you, brothers and sisters,","T":"Now, brothers and sisters, about the coming of our Lord Jesus Christ and our being gathered together to him—"},
    "2": {"L":"that you not be quickly shaken in mind or be alarmed, either by a spirit or by a spoken word or by a letter supposedly from us, to the effect that the day of the Lord has come.","M":"not to become easily unsettled or alarmed by the teaching allegedly from us—whether by a prophecy or by word of mouth or by letter—asserting that the day of the Lord has already come.","T":"please don't be easily alarmed or suddenly upset—whether by a prophecy or a message or a letter claiming to be from us—saying that the day of the Lord has already arrived."},
    "3": {"L":"Let no one deceive you in any way, for it will not come unless the rebellion comes first, and the man of lawlessness is revealed—the son of destruction,","M":"Don't let anyone deceive you in any way, for that day will not come until the rebellion occurs and the man of lawlessness is revealed, the man doomed to destruction.","T":"Don't let anyone fool you in any way. That day will not come until there is first a great rebellion against God, and the man of lawlessness—destined for destruction—is revealed."},
    "4": {"L":"who opposes and exalts himself above every so-called god or object of worship, so that he takes his seat in the temple of God, proclaiming himself to be God.","M":"He will oppose and will exalt himself over everything that is called God or is worshiped, so that he sets himself up in God's temple, proclaiming himself to be God.","T":"He will oppose and exalt himself above every so-called god and every object of worship. He will actually sit in the temple of God and declare himself to be God."},
    "5": {"L":"Do you not remember that when I was still with you I was telling you these things?","M":"Don't you remember that when I was with you I used to tell you these things?","T":"Don't you remember that I told you all this when I was with you?"},
    "6": {"L":"And you know what is restraining him now, so that he will be revealed in his time.","M":"And now you know what is holding him back, so that he may be revealed at the proper time.","T":"And you know what is currently holding him back—so that he will only be revealed at the right moment."},
    "7": {"L":"For the mystery of lawlessness is already at work; only the one who now restrains will do so until he is out of the way.","M":"For the secret power of lawlessness is already at work; but the one who now holds it back will continue to do so till he is taken out of the way.","T":"The secret power of lawlessness is already at work—but the one who is holding it back will continue to do so until he is removed."},
    "8": {"L":"And then the lawless one will be revealed, whom the Lord Jesus will slay with the breath of his mouth and bring to nothing by the brightness of his coming.","M":"And then the lawless one will be revealed, whom the Lord Jesus will overthrow with the breath of his mouth and destroy by the splendor of his coming.","T":"Then the lawless one will be revealed—and the Lord Jesus will destroy him with the breath of his mouth, eliminating him by the blazing splendor of his coming."},
    "9": {"L":"The coming of the lawless one is by the activity of Satan with all power and false signs and wonders,","M":"The coming of the lawless one will be in accordance with how Satan works. He will use all sorts of displays of power through signs and wonders that serve the lie,","T":"The lawless one's arrival will be accompanied by all the power of Satan, with counterfeit miracles and signs and wonders."},
    "10": {"L":"and with all the deception of wickedness for those who are perishing, because they did not accept the love of the truth so as to be saved.","M":"and all the ways that wickedness deceives those who are perishing. They perish because they refused to love the truth and so be saved.","T":"He will use every kind of evil deception on those who are perishing—because they refused to love the truth that could have saved them."},
    "11": {"L":"And for this reason God sends them a powerful delusion so that they will believe the lie,","M":"For this reason God sends them a powerful delusion so that they will believe the lie","T":"For this reason God allows a powerful delusion to overtake them, so they believe what is false—"},
    "12": {"L":"so that all who did not believe the truth but delighted in wickedness may be judged.","M":"and so that all will be condemned who have not believed the truth but have delighted in wickedness.","T":"so that all who refused to believe the truth and instead chose wickedness will be condemned."},
    "13": {"L":"But we are bound to give thanks to God always for you, brothers and sisters beloved by the Lord, because God chose you as the firstfruits for salvation through sanctification by the Spirit and belief in the truth.","M":"But we ought always to thank God for you, brothers and sisters loved by the Lord, because God chose you as firstfruits to be saved through the sanctifying work of the Spirit and through belief in the truth.","T":"But we must always thank God for you, brothers and sisters—you are loved by the Lord. God chose you from the beginning for salvation through the sanctifying work of the Spirit and through your belief in the truth."},
    "14": {"L":"To this end he also called you through our gospel, so that you may obtain the glory of our Lord Jesus Christ.","M":"He called you to this through our gospel, that you might share in the glory of our Lord Jesus Christ.","T":"He called you to this through the gospel we proclaimed, so you could share in the glory of our Lord Jesus Christ."},
    "15": {"L":"So then, brothers, stand firm and hold to the traditions that you were taught—whether by our word or by our letter.","M":"So then, brothers and sisters, stand firm and hold fast to the teachings we passed on to you, whether by word of mouth or by letter.","T":"So then, stand firm, brothers and sisters, and hold tightly to the teaching we passed on to you—in person or by letter."},
    "16": {"L":"Now may our Lord Jesus Christ himself, and God our Father, who loved us and gave us eternal encouragement and good hope through grace,","M":"May our Lord Jesus Christ himself and God our Father, who loved us and by his grace gave us eternal encouragement and good hope,","T":"May our Lord Jesus Christ himself and God our Father—who loved us and by his grace gave us eternal encouragement and good hope—"},
    "17": {"L":"comfort your hearts and strengthen you in every good work and word.","M":"encourage your hearts and strengthen you in every good deed and word.","T":"encourage your hearts and strengthen you in every good deed and word."}
  },
  "3": {
    "1": {"L":"Finally, brothers, pray for us that the word of the Lord may spread rapidly and be honored, as it was with you,","M":"As for other matters, brothers and sisters, pray for us that the message of the Lord may spread rapidly and be honored, just as it was with you.","T":"Brothers and sisters, please pray for us—that the Lord's message will spread quickly and be honored wherever it goes, just as it was with you."},
    "2": {"L":"and that we may be delivered from unreasonable and evil men, for not all have faith.","M":"And pray that we may be delivered from wicked and evil people, for not everyone has faith.","T":"And pray that we will be rescued from wicked and evil people—not everyone shares our faith."},
    "3": {"L":"But the Lord is faithful, who will strengthen you and guard you against the evil one.","M":"But the Lord is faithful, and he will strengthen you and protect you from the evil one.","T":"But the Lord is faithful. He will strengthen you and protect you from the evil one."},
    "4": {"L":"And we have confidence in the Lord concerning you, that you are doing and will continue to do the things that we command.","M":"We have confidence in the Lord that you are doing and will continue to do the things we command.","T":"We have confidence in the Lord that you are doing and will keep doing what we tell you."},
    "5": {"L":"May the Lord direct your hearts to the love of God and to the steadfastness of Christ.","M":"May the Lord direct your hearts into God's love and Christ's perseverance.","T":"May the Lord lead your hearts into a full understanding of God's love and the patient endurance that comes from Christ."},
    "6": {"L":"Now we command you, brothers, in the name of our Lord Jesus Christ, to keep away from any brother living in idleness and not according to the tradition that he received from us.","M":"In the name of the Lord Jesus Christ, we command you, brothers and sisters, to keep away from every believer who is idle and disruptive and does not live according to the teaching you received from us.","T":"In the name of the Lord Jesus Christ, we command you, brothers and sisters: stay away from any believer who refuses to work and ignores the instructions we gave."},
    "7": {"L":"For you yourselves know how you ought to imitate us, for we were not idle among you,","M":"For you yourselves know how you ought to follow our example. We were not idle when we were with you,","T":"You know very well that you should follow our example. We were not idle when we were with you—"},
    "8": {"L":"nor did we eat anyone's food without payment, but with labor and hardship, working night and day so as not to be a burden to any of you;","M":"nor did we eat anyone's food without paying for it. On the contrary, we worked night and day, laboring and toiling so that we would not be a burden to any of you.","T":"we didn't eat anyone's food without paying for it. We worked hard day and night so we wouldn't be a burden to any of you."},
    "9": {"L":"not because we do not have the right, but in order to give you an example to imitate.","M":"We did this, not because we do not have the right to such help, but in order to offer ourselves as a model for you to imitate.","T":"We had the right to ask for support, but we worked instead—to give you an example to follow."},
    "10": {"L":"For even when we were with you, we were giving you this command: If anyone is not willing to work, let him not eat.","M":"For even when we were with you, we gave you this rule: 'The one who is unwilling to work shall not eat.'","T":"Even when we were with you, we gave you this rule: 'If anyone refuses to work, they shouldn't eat either.'"},
    "11": {"L":"For we hear that some among you are living in idleness, not busy at work, but busybodies.","M":"We hear that some among you are idle and disruptive. They are not busy; they are busybodies.","T":"We've heard that some of you are not working at all—just meddling in other people's business."},
    "12": {"L":"Now such persons we command and encourage in the Lord Jesus Christ to work in quietness and to eat their own food.","M":"Such people we command and urge in the Lord Jesus Christ to settle down and earn the food they eat.","T":"We command and urge such people, in the name of the Lord Jesus Christ, to settle down and earn their own living."},
    "13": {"L":"But as for you, brothers, do not grow weary in doing good.","M":"And as for you, brothers and sisters, never tire of doing what is good.","T":"As for the rest of you—never grow tired of doing what is right."},
    "14": {"L":"But if anyone does not obey what we say in this letter, take note of that person and do not associate with him, so that he may be put to shame.","M":"Take special note of anyone who does not obey our instruction in this letter. Do not associate with them, in order that they may feel ashamed.","T":"If anyone refuses to follow the instructions in this letter, take note of them. Don't associate with them—let them feel ashamed of their behavior."},
    "15": {"L":"Yet do not regard him as an enemy, but warn him as a brother.","M":"Yet do not regard them as an enemy, but warn them as you would a fellow believer.","T":"But don't treat them as an enemy—correct them as a fellow believer."},
    "16": {"L":"Now may the Lord of peace himself give you peace at all times in every way. The Lord be with you all.","M":"Now may the Lord of peace himself give you peace at all times and in every way. The Lord be with all of you.","T":"May the Lord of peace himself give you his peace all the time in every situation. The Lord be with you all."},
    "17": {"L":"I, Paul, write this greeting with my own hand. This is the sign in every letter; this is how I write.","M":"I, Paul, write this greeting in my own hand, which is the distinguishing mark in all my letters. This is how I write.","T":"I, Paul, write this greeting in my own handwriting—this is my authenticating mark in every letter I write."},
    "18": {"L":"The grace of our Lord Jesus Christ be with you all.","M":"The grace of our Lord Jesus Christ be with you all.","T":"May the grace of our Lord Jesus Christ be with you all."}
  }
})

# ── 2 PETER ───────────────────────────────────────────────────────────────
write_book('2peter', {
  "1": {
    "1": {"L":"Simon Peter, a servant and apostle of Jesus Christ, to those who have received a faith of equal standing with ours through the righteousness of our God and Savior Jesus Christ:","M":"Simon Peter, a servant and apostle of Jesus Christ, To those who through the righteousness of our God and Savior Jesus Christ have received a faith as precious as ours:","T":"I, Simon Peter, a servant and apostle of Jesus Christ, am writing to those who have received the same precious faith as ours—made possible through the righteousness of our God and Savior Jesus Christ."},
    "2": {"L":"May grace and peace be multiplied to you in the knowledge of God and of Jesus our Lord.","M":"Grace and peace be yours in abundance through the knowledge of God and of Jesus our Lord.","T":"May grace and peace be multiplied to you through the knowledge of God and of Jesus our Lord."},
    "3": {"L":"His divine power has granted to us all things pertaining to life and godliness through the knowledge of him who called us by his own glory and excellence,","M":"His divine power has given us everything we need for a godly life through our knowledge of him who called us by his own glory and goodness.","T":"By his divine power, God has given us everything we need for life and godliness—through knowing him who called us by his own glory and moral excellence."},
    "4": {"L":"by which he has granted to us his precious and very great promises, so that through them you may become partakers of the divine nature, having escaped the corruption that is in the world because of sinful desire.","M":"Through these he has given us his very great and precious promises, so that through them you may participate in the divine nature, having escaped the corruption in the world caused by evil desires.","T":"Through these he has given us his precious and magnificent promises, so that through them you can escape the corruption that sinful desire brings and actually share in God's own nature."},
    "5": {"L":"For this very reason, making every effort, supply to your faith virtue, and to virtue knowledge,","M":"For this very reason, make every effort to add to your faith goodness; and to goodness, knowledge;","T":"For this reason, make every effort to add to your faith goodness; and to goodness, knowledge;"},
    "6": {"L":"and to knowledge self-control, and to self-control endurance, and to endurance godliness,","M":"and to knowledge, self-control; and to self-control, perseverance; and to perseverance, godliness;","T":"and to knowledge, self-control; and to self-control, perseverance; and to perseverance, godliness;"},
    "7": {"L":"and to godliness brotherly affection, and to brotherly affection love.","M":"and to godliness, mutual affection; and to mutual affection, love.","T":"and to godliness, mutual affection for believers; and to that, love."},
    "8": {"L":"For if these things are yours and are increasing, they keep you from being either ineffective or unfruitful in the knowledge of our Lord Jesus Christ.","M":"For if you possess these qualities in increasing measure, they will keep you from being ineffective and unproductive in your knowledge of our Lord Jesus Christ.","T":"If these qualities are increasingly growing in you, they will keep you from being ineffective and unproductive in your knowledge of our Lord Jesus Christ."},
    "9": {"L":"For whoever lacks these things is so nearsighted that he is blind, having forgotten the cleansing from his former sins.","M":"But whoever does not have them is nearsighted and blind, forgetting that they have been cleansed from their past sins.","T":"But those who lack these qualities are so shortsighted they are practically blind—they have forgotten that they were cleansed from their past sins."},
    "10": {"L":"Therefore, brothers, be all the more diligent to confirm your calling and election, for if you practice these things you will never stumble.","M":"Therefore, my brothers and sisters, make every effort to confirm your calling and election. For if you do these things, you will never stumble,","T":"So, brothers and sisters, be even more diligent to make your calling and election secure. If you do these things, you will never stumble—"},
    "11": {"L":"For in this way an entrance into the eternal kingdom of our Lord and Savior Jesus Christ will be richly provided to you.","M":"and you will receive a rich welcome into the eternal kingdom of our Lord and Savior Jesus Christ.","T":"and you will receive a grand welcome into the eternal kingdom of our Lord and Savior Jesus Christ."},
    "12": {"L":"Therefore I intend always to remind you about these things, even though you know them and are firmly established in the truth that you have.","M":"So I will always remind you of these things, even though you know them and are firmly established in the truth you now have.","T":"So I will always remind you of these things, even though you already know them and are established in the truth."},
    "13": {"L":"But I think it right, as long as I am in this body, to stir you up by way of reminder,","M":"I think it is right to refresh your memory as long as I live in the tent of this body,","T":"I think it is right, while I'm still living in this body, to keep refreshing your memory—"},
    "14": {"L":"knowing that the putting off of my body will come soon, as our Lord Jesus Christ made clear to me.","M":"because I know that I will soon put it aside, as our Lord Jesus Christ has made clear to me.","T":"knowing that I will soon die, as our Lord Jesus Christ has made clear to me."},
    "15": {"L":"And I will make every effort so that after my departure you will be able to recall these things at any time.","M":"And I will make every effort to see that after my departure you will always be able to remember these things.","T":"I will do everything I can to make sure you can remember these things even after I am gone."},
    "16": {"L":"For we did not follow cleverly devised myths when we made known to you the power and coming of our Lord Jesus Christ, but we were eyewitnesses of his majesty.","M":"For we did not follow cleverly devised stories when we told you about the coming of our Lord Jesus Christ in power, but we were eyewitnesses of his majesty.","T":"We did not follow cleverly invented myths when we told you about the power and coming of our Lord Jesus Christ—we were actual eyewitnesses of his majestic glory."},
    "17": {"L":"For when he received honor and glory from God the Father, and the voice was borne to him by the Majestic Glory: 'This is my beloved Son, with whom I am well pleased,'","M":"He received honor and glory from God the Father when the voice came to him from the Majestic Glory, saying, 'This is my Son, whom I love; with him I am well pleased.'","T":"He received honor and glory from God the Father when that voice came from the Majestic Glory: 'This is my Son, whom I love—I am completely pleased with him!'"},
    "18": {"L":"we ourselves heard this very voice borne from heaven, for we were with him on the holy mountain.","M":"We ourselves heard this voice that came from heaven when we were with him on the sacred mountain.","T":"We ourselves heard that voice from heaven when we were with him on the holy mountain."},
    "19": {"L":"And we have the prophetic word more fully confirmed, to which you do well to pay attention as to a lamp shining in a dark place, until the day dawns and the morning star rises in your hearts,","M":"We also have the prophetic message as something completely reliable, and you will do well to pay attention to it, as to a light shining in a dark place, until the day dawns and the morning star rises in your hearts.","T":"Because of this, we have even greater confidence in the message of the prophets. Pay careful attention to it, like a lamp shining in a dark place, until the day breaks and the morning star rises in your hearts."},
    "20": {"L":"knowing this first of all, that no prophecy of scripture comes from someone's own interpretation.","M":"Above all, you must understand that no prophecy of Scripture came about by the prophet's own interpretation of things.","T":"Above all, understand this: no prophecy of scripture ever came from the prophet's own understanding."},
    "21": {"L":"For no prophecy was ever produced by the will of man, but men spoke from God as they were carried along by the Holy Spirit.","M":"For prophecy never had its origin in the human will, but prophets, though human, spoke from God as they were carried along by the Holy Spirit.","T":"Prophecy never originated in human will. Instead, people spoke from God, carried along by the Holy Spirit."}
  },
  "2": {
    "1": {"L":"But false prophets also arose among the people, just as there will also be false teachers among you, who will secretly bring in destructive heresies, even denying the Master who bought them, bringing swift destruction upon themselves.","M":"But there were also false prophets among the people, just as there will be false teachers among you. They will secretly introduce destructive heresies, even denying the sovereign Lord who bought them—bringing swift destruction on themselves.","T":"But there were also false prophets among God's people in the past, just as there will be false teachers among you now. They will secretly introduce destructive heresies—even denying the Master who bought them—bringing swift destruction on themselves."},
    "2": {"L":"And many will follow their sensuality, and because of them the way of truth will be blasphemed.","M":"Many will follow their depraved conduct and will bring the way of truth into disrepute.","T":"Many will follow their shameful behavior, and the way of truth will be slandered because of them."},
    "3": {"L":"And in their greed they will exploit you with false words. Their condemnation from long ago is not idle, and their destruction is not asleep.","M":"In their greed these teachers will exploit you with fabricated stories. Their condemnation has long been hanging over them, and their destruction has not been sleeping.","T":"In their greed they will use you with their fabricated teachings to make money. Their judgment was set long ago, and their destruction is not sleeping."},
    "4": {"L":"For if God did not spare angels when they sinned, but cast them into hell and committed them to chains of gloomy darkness to be kept until the judgment;","M":"For if God did not spare angels when they sinned, but sent them to hell, putting them in chains of darkness to be held for judgment;","T":"God did not spare the angels who sinned—he threw them into hell and imprisoned them in dark chains until the day of judgment."},
    "5": {"L":"and did not spare the ancient world, but preserved Noah, a herald of righteousness, with seven others, when he brought a flood upon the world of the ungodly;","M":"if he did not spare the ancient world when he brought the flood on its ungodly people, but protected Noah, a preacher of righteousness, and seven others;","T":"He did not spare the ancient world—he brought the flood on those ungodly people, but he preserved Noah, a preacher of righteousness, along with seven others."},
    "6": {"L":"and if he condemned the cities of Sodom and Gomorrah to extinction, turning them to ashes—making them an example to those who were going to live in an ungodly way—","M":"if he condemned the cities of Sodom and Gomorrah by burning them to ashes, and made them an example of what is going to happen to the ungodly;","T":"He condemned the cities of Sodom and Gomorrah, burning them to ashes as a permanent warning to the ungodly of what is coming."},
    "7": {"L":"and if he rescued righteous Lot, who was greatly distressed by the sensual conduct of the lawless","M":"and if he rescued Lot, a righteous man, who was distressed by the depraved conduct of the lawless","T":"But he rescued Lot, a righteous man who was deeply distressed by the obscene behavior of the wicked around him."},
    "8": {"L":"(for by what he saw and heard as he lived among them, that righteous man was tormented in his righteous soul day after day with their lawless deeds),","M":"(for that righteous man, living among them day after day, was tormented in his righteous soul by the lawless deeds he saw and heard)—","T":"Day after day, living among those people, Lot's righteous soul was tormented by what he saw and heard."},
    "9": {"L":"then the Lord knows how to rescue the godly from trials, and to keep the unrighteous under punishment for the day of judgment,","M":"if this is so, then the Lord knows how to rescue the godly from trials and to hold the unrighteous for punishment on the day of judgment.","T":"If all that is true, then the Lord knows how to rescue godly people from trials and to hold the wicked for punishment on the day of judgment."},
    "10": {"L":"and especially those who indulge in the lust of defiling passion and despise authority. Presumptuous and self-willed, they do not tremble as they blaspheme the glorious ones,","M":"This is especially true of those who follow the corrupt desire of the flesh and despise authority. Bold and arrogant, they are not afraid to heap abuse on celestial beings;","T":"This is especially true of those who follow the corrupt desires of their sinful nature and despise authority. These bold and arrogant people are not afraid to insult the glorious beings—"},
    "11": {"L":"whereas angels, though greater in might and power, do not bring a slanderous judgment against them before the Lord.","M":"yet even angels, although they are stronger and more powerful, do not heap abuse on such beings when bringing judgment on them from the Lord.","T":"even though angels, who are far greater in strength and power, would never dare bring such insulting charges even against them before the Lord."},
    "12": {"L":"But these, as irrational animals—born to be caught and destroyed, blaspheming about matters they do not understand—will be destroyed in their own corruption,","M":"But these people blaspheme in matters they do not understand. They are like unreasoning animals, creatures of instinct, born only to be caught and destroyed, and like animals they too will perish.","T":"But these people are like mindless animals—born by instinct to be caught and destroyed. They mock what they don't understand, and like animals they will be destroyed,"},
    "13": {"L":"suffering wrong as the wages of their wrongdoing. They count it pleasure to revel in the daytime. They are blots and blemishes, reveling in their pleasures while they feast with you.","M":"They will be paid back with harm for the harm they have done. Their idea of pleasure is to carouse in broad daylight. They are blots and blemishes, reveling in their pleasures while they feast with you.","T":"being paid back harm for the harm they have caused. They consider it a pleasure to party in broad daylight—they are stains and blemishes, reveling in their lusts while eating with you."},
    "14": {"L":"They have eyes full of adultery, insatiable for sin, enticing unstable souls. They have hearts trained in greed—accursed children!","M":"With eyes full of adultery, they never stop sinning; they seduce the unstable; they are experts in greed—an accursed brood!","T":"With eyes full of lust, they never stop sinning. They lure unstable people into sin—experts in greed. God's curse is on them!"},
    "15": {"L":"Forsaking the right way, they have gone astray. They have followed the way of Balaam, the son of Bosor, who loved the wages of unrighteousness,","M":"They have left the straight way and wandered off to follow the way of Balaam son of Bezer, who loved the wages of wickedness.","T":"They have left the straight path and gone astray, following the path of Balaam son of Beor, who loved the money he could make by doing wrong."},
    "16": {"L":"but was rebuked for his own transgression—a speechless donkey spoke with a human voice and restrained the prophet's madness.","M":"But he was rebuked for his wrongdoing by a donkey—an animal without speech—who spoke with a human voice and restrained the prophet's madness.","T":"But Balaam was rebuked for his sin—a donkey, which cannot even speak, suddenly spoke with a human voice and stopped the prophet's madness!"},
    "17": {"L":"These are waterless springs and mists driven by a storm, for whom the gloom of darkness has been reserved.","M":"These people are springs without water and mists driven by a storm. Blackest darkness is reserved for them.","T":"These people are like dried-up springs, like fog driven away by a storm. The blackest darkness has been reserved for them."},
    "18": {"L":"For, speaking loud boasts of folly, they entice by sensual passions of the flesh those who are barely escaping from those who live in error.","M":"For they mouth empty, boastful words and, by appealing to the lustful desires of the flesh, they entice people who are just escaping from those who live in error.","T":"They speak empty, boastful words, and by appealing to people's sinful desires, they lure back those who are just beginning to escape from people who live in error."},
    "19": {"L":"They promise them freedom, but they themselves are slaves of corruption—for whatever overcomes a man, to that he is enslaved.","M":"They promise them freedom, while they themselves are slaves of depravity—for 'people are slaves to whatever has mastered them.'","T":"They promise freedom while they themselves are slaves to corruption—for you are a slave to whatever controls you."},
    "20": {"L":"For if, after they have escaped the defilements of the world through the knowledge of our Lord and Savior Jesus Christ, they are again entangled in them and overcome, the last state has become worse for them than the first.","M":"If they have escaped the corruption of the world by knowing our Lord and Savior Jesus Christ and are again entangled in it and are overcome, they are worse off at the end than they were at the beginning.","T":"If those who have escaped the world's corruption by knowing our Lord and Savior Jesus Christ are again entangled in it and overcome, they are worse off than they were before."},
    "21": {"L":"For it would have been better for them never to have known the way of righteousness than, after knowing it, to turn back from the holy commandment delivered to them.","M":"It would have been better for them not to have known the way of righteousness, than to have known it and then to turn their backs on the sacred command that was passed on to them.","T":"It would have been better for them never to have known the way of righteousness than to know it and then turn away from the holy command they were given."},
    "22": {"L":"What the true proverb says has happened to them: 'The dog has returned to its own vomit, and the sow, after washing herself, has returned to wallow in the mire.'","M":"Of them the proverbs are true: 'A dog returns to its vomit,' and, 'A sow that is washed returns to her wallowing in the mud.'","T":"The ancient proverbs describe them perfectly: 'A dog returns to its vomit,' and 'A washed pig goes back to rolling in the mud.'"}
  },
  "3": {
    "1": {"L":"This is now, beloved, the second letter I am writing to you. In both of them I am stirring up your sincere mind by way of reminder,","M":"Dear friends, this is now my second letter to you. I have written both of them as reminders to stimulate you to wholesome thinking.","T":"Dear friends, this is now my second letter to you. In both letters I am trying to stir up your thinking by way of reminder—"},
    "2": {"L":"so that you should remember the words spoken beforehand by the holy prophets and the commandment of the Lord and Savior through your apostles.","M":"I want you to recall the words spoken in the past by the holy prophets and the command given by our Lord and Savior through your apostles.","T":"I want you to recall the words spoken long ago by the holy prophets and the command our Lord and Savior gave through your apostles."},
    "3": {"L":"Know this first of all: that in the last days mockers will come with their mocking, walking after their own lusts,","M":"Above all, you must understand that in the last days scoffers will come, scoffing and following their own evil desires.","T":"Most importantly, understand that in the last days mockers will arrive who follow their own evil desires and scoff."},
    "4": {"L":"and saying: 'Where is the promise of his coming? For from the day the fathers fell asleep, all things are continuing just as they were from the beginning of creation.'","M":"They will say, 'Where is this coming he promised? Ever since our ancestors died, everything goes on as it has since the beginning of creation.'","T":"They will say, 'So where is this coming he promised? Ever since our ancestors died, everything has stayed exactly the same as it was at creation!'"},
    "5": {"L":"For it escapes them—this is their choice—that the heavens existed long ago, and the earth was formed out of water and through water by the word of God;","M":"But they deliberately forget that long ago by God's word the heavens came into being and the earth was formed out of water and by water.","T":"But they conveniently ignore that long ago by God's word the heavens came into existence and the earth was formed from water and through water—"},
    "6": {"L":"through which the world of that time was deluged with water and perished.","M":"By these waters also the world of that time was deluged and destroyed.","T":"and by that same water the ancient world was flooded and destroyed."},
    "7": {"L":"But by the same word the heavens and earth that now exist are stored up for fire, being kept until the day of judgment and destruction of the ungodly.","M":"By the same word the present heavens and earth are reserved for fire, being kept for the day of judgment and destruction of the ungodly.","T":"By that same word, the present heavens and earth are stored up for fire—reserved for the day when God will judge and destroy the ungodly."},
    "8": {"L":"But do not overlook this one fact, beloved: that with the Lord one day is as a thousand years, and a thousand years as one day.","M":"But do not forget this one thing, dear friends: With the Lord a day is like a thousand years, and a thousand years are like a day.","T":"Don't overlook this important fact, dear friends: with the Lord, a single day is like a thousand years, and a thousand years are like a single day."},
    "9": {"L":"The Lord is not slow to fulfill his promise as some count slowness, but is patient toward you, not wishing that any should perish but that all should reach repentance.","M":"The Lord is not slow in keeping his promise, as some understand slowness. Instead he is patient with you, not wanting anyone to perish, but everyone to come to repentance.","T":"The Lord isn't being slow about his promise—not slow by any human standard. He is being patient with you, not wanting anyone to perish but wanting everyone to come to repentance."},
    "10": {"L":"But the day of the Lord will come like a thief. On that day the heavens will pass away with a roar, and the heavenly bodies will burn up and be dissolved, and the earth and the works on it will be exposed.","M":"But the day of the Lord will come like a thief. The heavens will disappear with a roar; the elements will be destroyed by fire, and the earth and everything done in it will be laid bare.","T":"But the day of the Lord will arrive unexpectedly, like a thief. The heavens will disappear with a roar, the elements will be dissolved by fire, and everything on earth will be exposed."},
    "11": {"L":"Since all these things are thus to be dissolved, what sort of people ought you to be in holy conduct and godliness,","M":"Since everything will be destroyed in this way, what kind of people ought you to be? You ought to live holy and godly lives","T":"Since everything will be dissolved this way, what kind of people should you be? You should live holy and godly lives—"},
    "12": {"L":"waiting for and hastening the coming of the day of God, on account of which the heavens will be set on fire and dissolved, and the heavenly bodies will melt as they burn!","M":"as you look forward to the day of God and speed its coming. That day will bring about the destruction of the heavens by fire, and the elements will melt in the heat.","T":"looking forward to and actively working toward the coming of the day of God. On that day the heavens will be set on fire and dissolved, and the elements will melt in the heat."},
    "13": {"L":"But according to his promise we are waiting for new heavens and a new earth in which righteousness dwells.","M":"But in keeping with his promise we are looking forward to a new heaven and a new earth, where righteousness dwells.","T":"But we are waiting for what he promised: a new heaven and a new earth where righteousness is fully at home."},
    "14": {"L":"Therefore, beloved, since you are waiting for these things, make every effort to be found by him spotless and blameless, and at peace.","M":"So then, dear friends, since you are looking forward to this, make every effort to be found spotless, blameless and at peace with him.","T":"So then, dear friends, since you are looking forward to this, do everything you can to be found spotless, blameless, and at peace with him."},
    "15": {"L":"And count the patience of our Lord as salvation, just as our beloved brother Paul also wrote to you according to the wisdom given him,","M":"Bear in mind that our Lord's patience means salvation, just as our dear brother Paul also wrote you with the wisdom that God gave him.","T":"Remember that the Lord's patience is for the purpose of salvation—just as our dear brother Paul wrote to you with the wisdom God gave him."},
    "16": {"L":"speaking of these things as he does in all his letters, in which there are some things that are hard to understand, which the ignorant and unstable twist to their own destruction, as they do the other scriptures.","M":"He writes the same way in all his letters, speaking in them of these matters. His letters contain some things that are hard to understand, which ignorant and unstable people distort, as they do the other Scriptures, to their own destruction.","T":"He talks about these same things in all his letters. Some of what he writes is hard to understand, and ignorant and unstable people twist his words—and the other scriptures too—to their own destruction."},
    "17": {"L":"You therefore, beloved, knowing this beforehand, be on your guard so that you may not be led away by the error of lawless people and lose your own stability.","M":"Therefore, dear friends, since you have been forewarned, be on your guard so that you may not be carried away by the error of the lawless and fall from your secure position.","T":"So, dear friends, you've been warned in advance. Be on your guard—don't be carried away by the error of lawless people and fall from your secure position."},
    "18": {"L":"But grow in the grace and knowledge of our Lord and Savior Jesus Christ. To him be glory both now and to the day of eternity. Amen.","M":"But grow in the grace and knowledge of our Lord and Savior Jesus Christ. To him be glory both now and forever! Amen.","T":"Instead, grow in the grace and knowledge of our Lord and Savior Jesus Christ. To him be glory now and forever! Amen."}
  }
})

print('\nPhase 2 complete: Titus, 2 Thessalonians, 2 Peter')
